protected int findWrapPos(String text, int width, int startPos) {
    if (text == null || width <= 0 || startPos < 0 || startPos >= text.length()) {
        return -1;
    }
    int pos;
    // If the line ends before the max wrap pos or a newline char is found
    if (((pos = text.indexOf('\n', startPos)) != -1 && pos < startPos + width)
            || ((pos = text.indexOf('\r', startPos)) != -1 && pos < startPos + width)) {
        return pos + 1;
    }

    if (startPos + width >= text.length()) {
        return -1;
    }

    // Look for the last whitespace character (including tabs) before startPos+width
    pos = startPos + width - 1;

    while (pos > startPos) {
        char c = text.charAt(pos);
        if (c == ' ' || c == '\n' || c == '\r' || c == '\t') {
            break;
        }
        --pos;
    }

    // If we found a whitespace, return its position
    if (pos > startPos) {
        return pos;
    }

    // If no whitespace found, simply chop at startPos+width
    return startPos + width;
}

protected int findWrapPos(String text, int width, int startPos) {
    if (text == null || text.length() == 0 || startPos >= text.length()) {
        return -1;
    }
    int maxPos = startPos + width;

    // Adjust maxPos if it exceeds text length
    if (maxPos >= text.length()) {
        return -1;
    }

    // Check for newline or tab occurrence within width
    int newlinePos = text.indexOf('\n', startPos);
    int tabPos = text.indexOf('\t', startPos);
    if ((newlinePos != -1 && newlinePos <= maxPos) || (tabPos != -1 && tabPos <= maxPos)) {
        return Math.min(newlinePos, tabPos) + 1;
    }

    // Look for the last whitespace before maxPos
    int pos = maxPos;
    while (pos > startPos) {
        char c = text.charAt(pos);
        if (Character.isWhitespace(c)) {
            return pos;
        }
        pos--;
    }

    // If no whitespace found, return maxPos directly
    return maxPos;
}
